static void blake2b_compress(blake2b_state *S,
                             const uint8_t block[BLAKE2B_BLOCKBYTES]) {
  uint64_t m[16];
  uint64_t v[16];
  size_t i;
  for (i = 0; i < 16; ++i) {
    m[i] = load64(block + i * sizeof(m[i]));
